{ "action":"translate", "target":"<t>", "translate":{"x":0,"y":0,"z":0} }
{ "action":"set_position","target":"<t>","position":{"x":0,"y":0,"z":0} }
{ "action":"rotate", "target":"<t>", "rotate":{"x":0,"y":0,"z":90}, "unit":"deg" }
